/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The path length is fixed: (m-1) + (n-1) steps + 1 initial cell = m + n - 1 cells.
    // The problem constraints are m*n <= 1000.
    // Since m and n can be up to 1000, but m*n <= 1000, if one is large, the other must be small.
    // The maximum path length is around 1000.

    // We can use Dynamic Programming or BFS/DFS, but since we need the minimum XOR sum,
    // and the XOR operation doesn't satisfy the optimal substructure property easily (like min/max sum),
    // standard DP on the minimum value might not work directly if we only store one value per cell.

    // Since the maximum value is 1023 (10 bits), there are only 2^10 = 1024 possible XOR sums.
    // This suggests that we can use DP where the state includes the XOR sum.

    // dp[i][j] will be a Set storing all possible XOR sums to reach cell (i, j).
    const dp = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

    // Base case: starting cell (0, 0)
    dp[0][0].add(grid[0][0]);

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;

            const currentValue = grid[i][j];
            const possibleXORs = new Set();

            // From above (i-1, j)
            if (i > 0) {
                for (const xorSum of dp[i - 1][j]) {
                    possibleXORs.add(xorSum ^ currentValue);
                }
            }

            // From left (i, j-1)
            if (j > 0) {
                for (const xorSum of dp[i][j - 1]) {
                    possibleXORs.add(xorSum ^ currentValue);
                }
            }

            dp[i][j] = possibleXORs;
        }
    }

    // The result is the minimum value in the set dp[m-1][n-1]
    const finalXORs = dp[m - 1][n - 1];
    if (finalXORs.size === 0) {
        // Should not happen given problem constraints
        return -1;
    }

    let minXor = Infinity;
    for (const xorSum of finalXORs) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

