use std::collections::HashSet;

fn solve(grid: Vec<Vec<i64>>) -> i64 {
    let m = grid.len();
    if m == 0 {
        return 0;
    }
    let n = grid[0].len();
    if n == 0 {
        return 0;
    }

    // dp[i][j] will store a HashSet of all possible XOR sums to reach cell (i, j).
    // Since m*n <= 1000, and the maximum XOR sum is bounded by 1023 (2^10 - 1),
    // the size of the set at any cell will be at most 1024.
    // The total complexity will be O(m*n * |States|), where |States| <= 1024.
    // Given m*n <= 1000, this is feasible.

    // Using Vec<Vec<HashSet<i64>>> to represent the DP table
    let mut dp: Vec<Vec<HashSet<i64>>> = vec![vec![HashSet::new(); n]; m];

    // Base case: starting cell (0, 0)
    dp[0][0].insert(grid[0][0]);

    for i in 0..m {
        for j in 0..n {
            if i == 0 && j == 0 {
                continue;
            }

            let current_value = grid[i][j];
            let mut possible_xors = HashSet::new();

            // From above (i-1, j)
            if i > 0 {
                for &xor_sum in &dp[i - 1][j] {
                    possible_xors.insert(xor_sum ^ current_value);
                }
            }

            // From left (i, j-1)
            if j > 0 {
                for &xor_sum in &dp[i][j - 1] {
                    possible_xors.insert(xor_sum ^ current_value);
                }
            }

            dp[i][j] = possible_xors;
        }
    }

    // The result is the minimum value in the set dp[m-1][n-1]
    let final_xors = &dp[m - 1][n - 1];

    if final_xors.is_empty() {
        // Should not happen given problem constraints
        return -1; 
    }

    let mut min_xor = i64::MAX;
    for &xor_sum in final_xors.iter() {
        if xor_sum < min_xor {
            min_xor = xor_sum;
        }
    }

    min_xor
}
